{% extends "base.html" %}

{% block title %}Products — FIWARE Smart Store{% endblock %}

{% block content %}
<div class="section-header">
  <h1 data-i18n="page_products_title">Productos</h1>
  <p data-i18n="page_products_subtitle">Gestión del catálogo de productos</p>
</div>

<div class="card products-toolbar">
  <button id="btn-product-new" class="btn-primary" type="button">
    <i class="fas fa-plus" aria-hidden="true"></i>
    <span data-i18n="products_add_button">Añadir Product</span>
  </button>
</div>

<div class="card">
  <div class="products-table-wrap">
    <table class="products-table">
      <thead>
        <tr>
          <th data-i18n="products_col_image">Imagen</th>
          <th data-i18n="products_col_name">Nombre</th>
          <th data-i18n="products_col_color">Color</th>
          <th data-i18n="products_col_size">Size</th>
          <th data-i18n="products_col_origin">Origin Country</th>
          <th data-i18n="products_col_actions">Acciones</th>
        </tr>
      </thead>
      <tbody id="products-tbody"></tbody>
    </table>
  </div>
</div>

<div class="modal" id="product-modal" hidden>
  <div class="modal__backdrop" id="product-modal-close"></div>
  <div class="modal__panel" role="dialog" aria-modal="true" aria-labelledby="product-form-title">
    <h2 id="product-form-title" data-i18n="products_form_create">Nuevo Product</h2>
    <form id="product-form" novalidate>
      <input type="hidden" id="product-id" />
      <input type="hidden" id="existing-image" />

      <div class="form-grid">
        <label>
          <span data-i18n="products_field_name">Nombre</span>
          <input id="name" name="name" type="text" required minlength="2" maxlength="80" />
        </label>

        <label>
          <span data-i18n="products_field_price">Precio</span>
          <input id="price" name="price" type="number" min="0" step="0.01" required />
        </label>

        <label>
          <span data-i18n="products_field_size">Size</span>
          <select id="size" name="size" required>
            <option value="">--</option>
            <option value="S">S</option>
            <option value="M">M</option>
            <option value="L">L</option>
            <option value="XL">XL</option>
          </select>
        </label>

        <label>
          <span data-i18n="products_field_origin">Origin Country</span>
          <input id="originCountry" name="originCountry" type="text" required minlength="2" maxlength="56" />
        </label>

        <label>
          <span data-i18n="products_field_color">Color</span>
          <input id="color" name="color" type="color" required value="#4a90d9" />
        </label>

        <label>
          <span data-i18n="products_field_image_url">Image URL</span>
          <input id="image" name="image" type="url" placeholder="https://example.com/product.jpg" />
        </label>
      </div>

      <div class="form-actions">
        <button class="btn-primary" id="btn-save" type="submit" data-i18n="products_save">Guardar</button>
        <button class="btn-secondary" id="btn-cancel" type="button" data-i18n="products_cancel">Cancelar</button>
      </div>
    </form>
  </div>
</div>
{% endblock %}

{% block extra_scripts %}
<script>
  (function () {
    'use strict';

    var state = {
      products: []
    };

    var tbody = document.getElementById('products-tbody');
    var modal = document.getElementById('product-modal');
    var modalClose = document.getElementById('product-modal-close');
    var form = document.getElementById('product-form');
    var formTitle = document.getElementById('product-form-title');

    var GENERIC_PRODUCT_IMAGE = 'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><rect width="100" height="100" rx="12" fill="%23f3f4f6"/><circle cx="35" cy="55" r="18" fill="%23ef4444"/><circle cx="62" cy="48" r="16" fill="%23f59e0b"/><ellipse cx="50" cy="30" rx="12" ry="7" fill="%2322c55e"/></svg>';

    var PRODUCT_IMAGES = {
      apples: 'https://images.unsplash.com/photo-1630563451961-ac2ff27616ab?auto=format&fit=crop&w=320&q=80',
      bananas: 'https://images.unsplash.com/photo-1587132137056-bfbf0166836e?auto=format&fit=crop&w=320&q=80',
      coconuts: 'https://images.unsplash.com/photo-1581453883350-288b2c19bea8?auto=format&fit=crop&w=320&q=80',
      melons: 'https://images.unsplash.com/photo-1571575173700-afb9492e6a50?auto=format&fit=crop&w=320&q=80',
      'kiwi fruits': 'https://images.unsplash.com/photo-1679065103638-7360cb935fac?auto=format&fit=crop&w=320&q=80',
      strawberries: 'https://images.unsplash.com/photo-1601004890684-d8cbf643f5f2?auto=format&fit=crop&w=320&q=80',
      raspberries: 'https://images.unsplash.com/photo-1577069861033-55d04cec4ef5?auto=format&fit=crop&w=320&q=80',
      pineapples: 'https://images.unsplash.com/photo-1589820296156-2454bb8a6ad1?auto=format&fit=crop&w=320&q=80',
      oranges: 'https://images.unsplash.com/photo-1557800636-894a64c1696f?auto=format&fit=crop&w=320&q=80',
      blueberries: 'https://images.unsplash.com/photo-1594002348772-bc0cb57ade8b?auto=format&fit=crop&w=320&q=80'
    };

    function t(key, fallback) {
      if (!window.i18n || typeof window.i18n.t !== 'function') return fallback || key;
      var text = window.i18n.t(key);
      return text === key ? (fallback || key) : text;
    }

    function escapeHtml(value) {
      return String(value || '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
    }

    function normalizeProductName(name) {
      return String(name || '').trim().toLowerCase();
    }

    function imageForProduct(productName, currentImage) {
      var mapped = PRODUCT_IMAGES[normalizeProductName(productName)];
      if (mapped) return mapped;
      return currentImage || GENERIC_PRODUCT_IMAGE;
    }

    function attachImageFallbackHandlers() {
      document.querySelectorAll('.product-thumb').forEach(function (img) {
        img.addEventListener('error', function () {
          var fallback = img.getAttribute('data-fallback') || GENERIC_PRODUCT_IMAGE;
          if (img.getAttribute('data-error-applied') === '1') return;
          img.setAttribute('data-error-applied', '1');
          img.src = fallback;
        });
      });
    }

    function renderProducts() {
      if (!state.products.length) {
        tbody.innerHTML = '<tr><td colspan="6" class="text-muted">' + t('products_empty', 'No products found') + '</td></tr>';
        return;
      }

      tbody.innerHTML = state.products.map(function (product) {
        var image = imageForProduct(product.name, product.image);
        var color = product.color || '#cccccc';

        return '<tr class="product-row-clickable" data-detail-url="/products/' + encodeURIComponent(product.id) + '">' 
          + '<td><img class="product-thumb" src="' + escapeHtml(image) + '" data-fallback="' + escapeHtml(GENERIC_PRODUCT_IMAGE) + '" alt="' + escapeHtml(product.name) + '" /></td>'
          + '<td><a href="/products/' + encodeURIComponent(product.id) + '" class="product-name-link">' + escapeHtml(product.name) + '</a></td>'
          + '<td><span class="color-chip" style="background:' + escapeHtml(color) + '" title="' + escapeHtml(color) + '"></span> ' + escapeHtml(color) + '</td>'
          + '<td>' + escapeHtml(product.size || '-') + '</td>'
          + '<td>' + escapeHtml(product.originCountry || '-') + '</td>'
          + '<td>'
            + '<button class="btn-secondary btn-small" type="button" data-action="edit" data-id="' + escapeHtml(product.id) + '"><i class="fas fa-pen"></i> ' + t('products_edit', 'Editar') + '</button> '
            + '<button class="btn-danger btn-small" type="button" data-action="delete" data-id="' + escapeHtml(product.id) + '"><i class="fas fa-trash"></i> ' + t('products_delete', 'Borrar') + '</button>'
          + '</td>'
        + '</tr>';
      }).join('');

      attachImageFallbackHandlers();
    }

    async function loadProducts() {
      var response = await fetch('/api/products');
      if (!response.ok) throw new Error('Cannot load products');
      state.products = await response.json();
      renderProducts();
    }

    function openCreateForm() {
      form.reset();
      document.getElementById('product-id').value = '';
      document.getElementById('existing-image').value = '';
      formTitle.textContent = t('products_form_create', 'Nuevo Product');
      modal.hidden = false;
    }

    function openEditForm(productId) {
      var product = state.products.find(function (item) { return item.id === productId; });
      if (!product) return;

      form.reset();
      document.getElementById('product-id').value = product.id;
      document.getElementById('name').value = product.name || '';
      document.getElementById('price').value = product.price != null ? product.price : '';
      document.getElementById('size').value = product.size || '';
      document.getElementById('originCountry').value = product.originCountry || '';
      document.getElementById('color').value = /^#[0-9A-Fa-f]{6}$/.test(product.color || '') ? product.color : '#4a90d9';
      var productImage = imageForProduct(product.name, product.image);
      document.getElementById('image').value = productImage;
      document.getElementById('existing-image').value = productImage;
      formTitle.textContent = t('products_form_edit', 'Editar Product');
      modal.hidden = false;
    }

    function closeForm() {
      modal.hidden = true;
    }

    async function validateAndBuildPayload() {
      if (!form.checkValidity()) {
        form.reportValidity();
        return null;
      }

      var color = document.getElementById('color').value;
      if (!/^#[0-9A-Fa-f]{6}$/.test(color)) {
        alert(t('products_error_color', 'Invalid hex color.'));
        return null;
      }

      var imageUrl = document.getElementById('image').value.trim();
      var existingImage = document.getElementById('existing-image').value;

      var typedName = document.getElementById('name').value.trim();
      var mappedImage = imageForProduct(typedName, imageUrl || existingImage);

      return {
        name: typedName,
        price: Number(document.getElementById('price').value),
        size: document.getElementById('size').value,
        originCountry: document.getElementById('originCountry').value.trim(),
        color: color,
        image: mappedImage
      };
    }

    async function saveProduct(event) {
      event.preventDefault();

      var payload = await validateAndBuildPayload();
      if (!payload) return;

      var productId = document.getElementById('product-id').value;
      var isEdit = Boolean(productId);
      var url = isEdit ? '/api/products/' + encodeURIComponent(productId) : '/api/products';
      var method = isEdit ? 'PUT' : 'POST';

      var response = await fetch(url, {
        method: method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      if (!response.ok) {
        alert(t('products_error_save', 'Could not save product.'));
        return;
      }

      closeForm();
      await loadProducts();
    }

    async function deleteProduct(productId) {
      var confirmMessage = t('products_confirm_delete', 'Are you sure you want to delete this product?');
      if (!window.confirm(confirmMessage)) {
        return;
      }

      var response = await fetch('/api/products/' + encodeURIComponent(productId), {
        method: 'DELETE'
      });

      if (!response.ok) {
        alert(t('products_error_delete', 'Could not delete product.'));
        return;
      }

      await loadProducts();
    }

    document.getElementById('btn-product-new').addEventListener('click', openCreateForm);
    document.getElementById('btn-cancel').addEventListener('click', closeForm);
    modalClose.addEventListener('click', closeForm);
    form.addEventListener('submit', saveProduct);

    tbody.addEventListener('click', function (event) {
      var button = event.target.closest('button[data-action]');
      if (button) {
        var action = button.getAttribute('data-action');
        var id = button.getAttribute('data-id');

        if (action === 'edit') openEditForm(id);
        if (action === 'delete') deleteProduct(id);
        return;
      }

      var row = event.target.closest('tr.product-row-clickable');
      if (!row) return;
      var detailUrl = row.getAttribute('data-detail-url');
      if (detailUrl) {
        window.location.href = detailUrl;
      }
    });

    document.addEventListener('DOMContentLoaded', function () {
      loadProducts().catch(function () {
        tbody.innerHTML = '<tr><td colspan="6" class="text-muted">' + t('products_error_load', 'Error loading products') + '</td></tr>';
      });
    });
  }());
</script>
{% endblock %}

/* ============================================================
   theme.css — CSS-first theming via data-theme attribute
   All colors are declared as CSS custom properties.
   JS only toggles [data-theme] on <html> and persists to localStorage.
   ============================================================ */

/* ---------- Light theme (default) ---------- */
:root,
:root[data-theme="light"] {
  --bg:           #f4f4f9;
  --bg-alt:       #ffffff;
  --bg-nav:       #1a1a2e;
  --fg:           #1a1a2e;
  --fg-muted:     #555577;
  --accent:       #4a90d9;
  --accent-hover: #2f72bb;
  --border:       #d0d0e0;
  --shadow:       rgba(0, 0, 0, 0.08);
  --nav-fg:       #e0e0f0;
  --nav-active:   #4a90d9;
  --nav-hover-bg: rgba(255, 255, 255, 0.08);
  --footer-bg:    #1a1a2e;
  --footer-fg:    #a0a0c0;
  --btn-bg:       #4a90d9;
  --btn-fg:       #ffffff;
  --btn-border:   transparent;
  --card-bg:      #ffffff;
  --card-shadow:  0 4px 12px rgba(0, 0, 0, 0.08);
  --badge-bg:     #e8f0fb;
  --badge-fg:     #2f72bb;
}

/* ---------- Dark theme ---------- */
:root[data-theme="dark"] {
  --bg:           #0f0f1a;
  --bg-alt:       #1a1a2e;
  --bg-nav:       #0a0a14;
  --fg:           #e0e0f0;
  --fg-muted:     #8888aa;
  --accent:       #5ba3f5;
  --accent-hover: #7dbcff;
  --border:       #2a2a40;
  --shadow:       rgba(0, 0, 0, 0.4);
  --nav-fg:       #c0c0e0;
  --nav-active:   #5ba3f5;
  --nav-hover-bg: rgba(255, 255, 255, 0.05);
  --footer-bg:    #0a0a14;
  --footer-fg:    #666688;
  --btn-bg:       #2a3a5a;
  --btn-fg:       #c0d8ff;
  --btn-border:   #3a4a7a;
  --card-bg:      #1a1a2e;
  --card-shadow:  0 4px 12px rgba(0, 0, 0, 0.4);
  --badge-bg:     #1e2a40;
  --badge-fg:     #7dbcff;
}

/* ============================================================
   Base reset & common styles
   ============================================================ */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  font-size: 16px;
  line-height: 1.6;
  background-color: var(--bg);
  color: var(--fg);
  transition: background-color 0.25s ease, color 0.25s ease;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

a {
  color: var(--accent);
  text-decoration: none;
}

a:hover {
  color: var(--accent-hover);
  text-decoration: underline;
}

/* ============================================================
   Navbar
   ============================================================ */

.navbar {
  position: sticky;
  top: 0;
  z-index: 1000;
  background-color: var(--bg-nav);
  color: var(--nav-fg);
  box-shadow: 0 2px 8px var(--shadow);
  transition: background-color 0.25s ease;
}

.navbar-inner {
  display: flex;
  align-items: center;
  max-width: 1280px;
  margin: 0 auto;
  padding: 0 1.5rem;
  height: 3.5rem;
  gap: 0.5rem;
}

.navbar-brand {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--nav-fg);
  white-space: nowrap;
  margin-right: 1.5rem;
  text-decoration: none;
  letter-spacing: 0.03em;
}

.navbar-brand:hover {
  color: var(--nav-active);
  text-decoration: none;
}

.navbar-brand i {
  margin-right: 0.4rem;
  color: var(--nav-active);
}

.navbar-links {
  display: flex;
  align-items: center;
  list-style: none;
  margin: 0;
  padding: 0;
  gap: 0.25rem;
  flex: 1;
}

.navbar-links li a {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.4rem 0.85rem;
  border-radius: 6px;
  color: var(--nav-fg);
  font-size: 0.9rem;
  font-weight: 500;
  white-space: nowrap;
  transition: background-color 0.15s ease, color 0.15s ease;
  text-decoration: none;
}

.navbar-links li a:hover {
  background-color: var(--nav-hover-bg);
  color: var(--nav-active);
  text-decoration: none;
}

/* Active link — set by JS via class "active" */
.navbar-links li a.active {
  color: var(--nav-active);
  border-bottom: 2px solid var(--nav-active);
  font-weight: 700;
}

/* ---- Toggle buttons ---- */
.navbar-controls {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-left: auto;
}

.btn-toggle {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.35rem 0.75rem;
  border-radius: 6px;
  background-color: var(--btn-bg);
  color: var(--btn-fg);
  border: 1px solid var(--btn-border);
  font-size: 0.82rem;
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.15s ease, color 0.15s ease, border-color 0.15s ease;
  white-space: nowrap;
}

.btn-toggle:hover {
  background-color: var(--accent);
  color: #fff;
  border-color: var(--accent);
}

/* Hide the light-icon when in light mode and dark-icon when in dark mode */
:root[data-theme="light"] #icon-dark  { display: inline; }
:root[data-theme="light"] #icon-light { display: none; }
:root[data-theme="dark"]  #icon-dark  { display: none; }
:root[data-theme="dark"]  #icon-light { display: inline; }

/* ============================================================
   Main content wrapper
   ============================================================ */

.main-content {
  flex: 1;
  max-width: 1280px;
  width: 100%;
  margin: 0 auto;
  padding: 2rem 1.5rem;
}

/* ============================================================
   Cards
   ============================================================ */

.card {
  background-color: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  padding: 1.5rem;
  margin-bottom: 1.5rem;
  transition: background-color 0.25s ease, border-color 0.25s ease;
}

/* ============================================================
   Status banners (health indicator)
   ============================================================ */

.status {
  padding: 0.75rem 1rem;
  margin-top: 1rem;
  border-radius: 6px;
  font-size: 0.9rem;
}

.status.ok {
  background-color: #d4edda;
  color: #155724;
  border: 1px solid #c3e6cb;
}

.status.error {
  background-color: #f8d7da;
  color: #721c24;
  border: 1px solid #f5c6cb;
}

:root[data-theme="dark"] .status.ok {
  background-color: #1a3a2a;
  color: #6fde9e;
  border-color: #2a5a40;
}

:root[data-theme="dark"] .status.error {
  background-color: #3a1a1a;
  color: #f08080;
  border-color: #5a2a2a;
}

/* ============================================================
   Section headers
   ============================================================ */

.section-header {
  margin-bottom: 1.5rem;
}

.section-header h1 {
  font-size: 1.8rem;
  font-weight: 700;
  margin: 0 0 0.25rem;
  color: var(--fg);
}

.section-header p {
  font-size: 1rem;
  color: var(--fg-muted);
  margin: 0;
}

/* ============================================================
   Footer
   ============================================================ */

.footer {
  background-color: var(--footer-bg);
  color: var(--footer-fg);
  padding: 1.25rem 1.5rem;
  text-align: center;
  font-size: 0.82rem;
  transition: background-color 0.25s ease;
}

.footer a {
  color: var(--accent);
}

/* ============================================================
   Utility
   ============================================================ */

.text-muted {
  color: var(--fg-muted);
}

.badge {
  display: inline-block;
  padding: 0.2em 0.6em;
  border-radius: 4px;
  font-size: 0.78rem;
  font-weight: 600;
  background-color: var(--badge-bg);
  color: var(--badge-fg);
}

/* ============================================================
   Statistics Cards Grid
   ============================================================ */

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
}

.stat-card {
  display: flex;
  align-items: center;
  padding: 1.5rem;
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  cursor: pointer;
}

.stat-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 16px var(--shadow);
}

.stat-icon {
  font-size: 2.5rem;
  margin-right: 1.5rem;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 80px;
  height: 80px;
  border-radius: 8px;
}

.stat-content h3 {
  margin: 0 0 0.5rem;
  font-size: 0.95rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  opacity: 0.85;
}

.stat-number {
  margin: 0;
  font-size: 2rem;
  font-weight: 700;
}

/* Color schemes for each stat card */
.stat-stores {
  background: linear-gradient(135deg, #FF6B6B 0%, #FF8E8E 100%);
  color: #ffffff;
}

.stat-stores .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

.stat-products {
  background: linear-gradient(135deg, #4ECDC4 0%, #6FE0DD 100%);
  color: #ffffff;
}

.stat-products .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

.stat-employees {
  background: linear-gradient(135deg, #95E1D3 0%, #B5EFE1 100%);
  color: #1a1a2e;
}

.stat-employees .stat-icon {
  background-color: rgba(26, 26, 46, 0.1);
  color: #1a1a2e;
}

.stat-inventory {
  background: linear-gradient(135deg, #F38181 0%, #F5A6A6 100%);
  color: #ffffff;
}

.stat-inventory .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

/* Dark theme adjustments for stat cards */
:root[data-theme="dark"] .stat-stores {
  background: linear-gradient(135deg, #c94545 0%, #d95959 100%);
}

:root[data-theme="dark"] .stat-products {
  background: linear-gradient(135deg, #3a9b95 0%, #4db5ac 100%);
}

:root[data-theme="dark"] .stat-employees {
  background: linear-gradient(135deg, #6fb8a6 0%, #86cbb5 100%);
  color: #ffffff;
}

:root[data-theme="dark"] .stat-employees .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

:root[data-theme="dark"] .stat-inventory {
  background: linear-gradient(135deg, #c96668 0%, #d97d7e 100%);
}

/* ============================================================
   Mermaid Diagram Container
   ============================================================ */

.mermaid-container {
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 1.5rem;
  overflow-x: auto;
  background-color: var(--bg-alt);
  border-radius: 8px;
  border: 1px solid var(--border);
  min-height: 400px;
}

.mermaid {
  display: flex;
  justify-content: center;
  align-items: center;
  max-width: 100%;
}

/* SVG text in Mermaid diagrams inherit text color from theme */
.mermaid svg {
  max-width: 100%;
  height: auto;
}

.mermaid text {
  fill: var(--fg);
}

.mermaid line,
.mermaid path,
.mermaid polyline,
.mermaid polygon {
  stroke: var(--fg-muted);
}

/* Dark theme adjustments for Mermaid */
:root[data-theme="dark"] .mermaid text {
  fill: var(--fg);
}

:root[data-theme="dark"] .mermaid line,
:root[data-theme="dark"] .mermaid path {
  stroke: var(--fg-muted);
}

/* ============================================================
   Products view
   ============================================================ */

.products-toolbar {
  display: flex;
  justify-content: flex-start;
}

.modal[hidden] {
  display: none;
}

.modal {
  position: fixed;
  inset: 0;
  z-index: 2000;
}

.modal__backdrop {
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.45);
}

.modal__panel {
  position: relative;
  width: min(820px, calc(100% - 2rem));
  max-height: calc(100vh - 4rem);
  overflow-y: auto;
  margin: 2rem auto;
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  padding: 1.25rem;
}

.products-table-wrap {
  overflow-x: auto;
}

.products-table {
  width: 100%;
  border-collapse: collapse;
  min-width: 800px;
}

.products-table th,
.products-table td {
  border-bottom: 1px solid var(--border);
  padding: 0.75rem;
  text-align: left;
  vertical-align: middle;
}

.products-table th {
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--fg-muted);
}

.product-thumb {
  width: 52px;
  height: 52px;
  border-radius: 8px;
  object-fit: cover;
  border: 1px solid var(--border);
}

.color-chip {
  display: inline-block;
  width: 1rem;
  height: 1rem;
  border-radius: 3px;
  border: 1px solid var(--border);
  margin-right: 0.35rem;
  vertical-align: middle;
}

.form-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1rem;
}

.form-grid label,
.form-grid fieldset {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  margin: 0;
}

.form-grid input,
.form-grid select {
  background: var(--bg-alt);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 0.5rem 0.65rem;
}

.inline-label {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
}

.form-actions {
  margin-top: 1rem;
  display: flex;
  gap: 0.6rem;
}

.btn-primary,
.btn-secondary,
.btn-danger {
  border: 1px solid var(--btn-border);
  border-radius: 6px;
  padding: 0.45rem 0.75rem;
  cursor: pointer;
  font-weight: 600;
}

.btn-primary {
  background: var(--accent);
  color: #fff;
  border-color: var(--accent);
}

.btn-secondary {
  background: var(--bg-alt);
  color: var(--fg);
  border-color: var(--border);
}

.btn-danger {
  background: #d9534f;
  color: #fff;
  border-color: #d9534f;
}

.btn-small {
  font-size: 0.8rem;
  padding: 0.32rem 0.55rem;
}

.product-row-clickable {
  cursor: pointer;
}

.product-row-clickable:hover td {
  background-color: var(--bg-alt);
}

