  <div class="product-detail-header-row">
    <a href="/products" class="btn-secondary btn-small" data-i18n="product_detail_back">
      <i class="fas fa-arrow-left" aria-hidden="true"></i>
      <span data-i18n="product_detail_back">← Volver a Productos</span>
    </a>
  </div>
</div>

<!-- Product header card -->
<div class="card product-detail-card">
  <div class="product-detail-hero">
    <div class="product-detail-media">
      <img
        id="detail-product-img"
        class="product-detail-img"
        src="{{ product.image or '' }}"
        alt="{{ product.name }}"
        onerror="this.onerror=null;this.src=window.GENERIC_PRODUCT_IMAGE||''"
      />
    </div>
    <div class="product-detail-meta">
      <h1 class="product-detail-name">{{ product.name }}</h1>
      <ul class="product-attr-list">
        <li class="product-attr-item">
          <i class="fas fa-tag" aria-hidden="true"></i>
          <span class="attr-label" data-i18n="products_field_price">Precio</span>
          <strong class="attr-value">{{ "%.2f"|format(product.price|float) }} €</strong>
        </li>
        <li class="product-attr-item">
          <i class="fas fa-ruler" aria-hidden="true"></i>
          <span class="attr-label" data-i18n="products_field_size">Size</span>
          <strong class="attr-value">{{ product.size or '-' }}</strong>
        </li>
        <li class="product-attr-item">
          <i class="fas fa-globe" aria-hidden="true"></i>
          <span class="attr-label" data-i18n="products_field_origin">Origin Country</span>
          <strong class="attr-value">{{ product.originCountry or '-' }}</strong>
        </li>
        <li class="product-attr-item color-attr-item">
          <i class="fas fa-palette" aria-hidden="true"></i>
          <span class="attr-label" data-i18n="products_field_color">Color</span>
          <span class="product-color-swatch" style="background:{{ product.color or '#cccccc' }};"></span>
          <strong class="attr-value">{{ product.color or '-' }}</strong>
        </li>
      </ul>
      <div class="product-detail-actions">
        <button id="btn-edit-product" class="btn-secondary" type="button">
          <i class="fas fa-pen" aria-hidden="true"></i>
          <span data-i18n="products_edit">Editar</span>
        </button>
        <button id="btn-delete-product" class="btn-danger" type="button">
          <i class="fas fa-trash" aria-hidden="true"></i>
          <span data-i18n="products_delete">Borrar</span>
        </button>
      </div>
    </div>
  </div>
</div>

<!-- Inventory grouped by Store -->
<div class="card">
  <h2 class="section-title" data-i18n="product_detail_inventory_title">Disponibilidad por Tienda</h2>
  <div id="inventory-container">
    <!-- rendered by JS -->
  </div>
</div>

<!-- Edit product modal (same form as list.html, no duplication via server data) -->
<div class="modal" id="product-modal" hidden>
  <div class="modal__backdrop" id="product-modal-close"></div>
  <div class="modal__panel" role="dialog" aria-modal="true" aria-labelledby="product-form-title">
    <h2 id="product-form-title" data-i18n="products_form_edit">Editar Product</h2>
    <form id="product-form" novalidate>
      <input type="hidden" id="product-id" />
      <input type="hidden" id="existing-image" />

      <div class="form-grid">
        <label>
          <span data-i18n="products_field_name">Nombre</span>
          <input id="name" name="name" type="text" required minlength="2" maxlength="80" />
        </label>

        <label>
          <span data-i18n="products_field_price">Precio</span>
          <input id="price" name="price" type="number" min="0" step="0.01" required />
        </label>

        <label>
          <span data-i18n="products_field_size">Size</span>
          <select id="size" name="size" required>
            <option value="">--</option>
            <option value="S">S</option>
            <option value="M">M</option>
            <option value="L">L</option>
            <option value="XL">XL</option>
          </select>
        </label>

        <label>
          <span data-i18n="products_field_origin">Origin Country</span>
          <input id="originCountry" name="originCountry" type="text" required minlength="2" maxlength="56" />
        </label>

        <label>
          <span data-i18n="products_field_color">Color</span>
          <input id="color" name="color" type="color" required value="#4a90d9" />
        </label>

        <label>
          <span data-i18n="products_field_image_url">Image URL</span>
          <input id="image" name="image" type="url" placeholder="https://example.com/product.jpg" />
        </label>
      </div>

      <div class="form-actions">
        <button class="btn-primary" id="btn-save" type="submit" data-i18n="products_save">Guardar</button>
        <button class="btn-secondary" id="btn-cancel" type="button" data-i18n="products_cancel">Cancelar</button>
      </div>
    </form>
  </div>
</div>
{% endblock %}

{% block extra_scripts %}
<script>
(function () {
  'use strict';

  var PRODUCT = {{ product | tojson }};
  var INVENTORY_GROUPS = {{ inventory_groups | tojson }};
  var PRODUCT_ID = PRODUCT.id;

  var GENERIC_PRODUCT_IMAGE = 'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><rect width="100" height="100" rx="12" fill="%23f3f4f6"/><circle cx="35" cy="55" r="18" fill="%23ef4444"/><circle cx="62" cy="48" r="16" fill="%23f59e0b"/><ellipse cx="50" cy="30" rx="12" ry="7" fill="%2322c55e"/></svg>';
  window.GENERIC_PRODUCT_IMAGE = GENERIC_PRODUCT_IMAGE;

  var PRODUCT_IMAGES = {
    apples: 'https://images.unsplash.com/photo-1630563451961-ac2ff27616ab?auto=format&fit=crop&w=320&q=80',
    bananas: 'https://images.unsplash.com/photo-1587132137056-bfbf0166836e?auto=format&fit=crop&w=320&q=80',
    coconuts: 'https://images.unsplash.com/photo-1581453883350-288b2c19bea8?auto=format&fit=crop&w=320&q=80',
    melons: 'https://images.unsplash.com/photo-1571575173700-afb9492e6a50?auto=format&fit=crop&w=320&q=80',
    'kiwi fruits': 'https://images.unsplash.com/photo-1679065103638-7360cb935fac?auto=format&fit=crop&w=320&q=80',
    strawberries: 'https://images.unsplash.com/photo-1601004890684-d8cbf643f5f2?auto=format&fit=crop&w=320&q=80',
    raspberries: 'https://images.unsplash.com/photo-1577069861033-55d04cec4ef5?auto=format&fit=crop&w=320&q=80',
    pineapples: 'https://images.unsplash.com/photo-1589820296156-2454bb8a6ad1?auto=format&fit=crop&w=320&q=80',
    oranges: 'https://images.unsplash.com/photo-1557800636-894a64c1696f?auto=format&fit=crop&w=320&q=80',
    blueberries: 'https://images.unsplash.com/photo-1594002348772-bc0cb57ade8b?auto=format&fit=crop&w=320&q=80'
  };

  function t(key, fallback) {
    if (!window.i18n || typeof window.i18n.t !== 'function') return fallback || key;
    var text = window.i18n.t(key);
    return text === key ? (fallback || key) : text;
  }

  function escapeHtml(value) {
    return String(value || '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function imageForProduct(productName, currentImage) {
    var key = String(productName || '').trim().toLowerCase();
    return PRODUCT_IMAGES[key] || currentImage || GENERIC_PRODUCT_IMAGE;
  }

  function stockClass(value) {
    var count = Number(value) || 0;
    if (count >= 15) return 'badge-stock-high';
    if (count >= 6) return 'badge-stock-medium';
    return 'badge-stock-low';
  }

  // -------------------------------------------------------------------------
  // Fix product header image
  // -------------------------------------------------------------------------
  (function fixHeaderImage() {
    var img = document.getElementById('detail-product-img');
    if (!img) return;
    var resolved = imageForProduct(PRODUCT.name, PRODUCT.image);
    img.src = resolved;
    img.onerror = function () {
      if (img.getAttribute('data-error') === '1') return;
      img.setAttribute('data-error', '1');
      img.src = GENERIC_PRODUCT_IMAGE;
    };
  }());

  // -------------------------------------------------------------------------
  // Inventory rendering
  // -------------------------------------------------------------------------
  var container = document.getElementById('inventory-container');

  function renderInventory(groups) {
    if (!groups || !groups.length) {
      container.innerHTML = '<p class="text-muted inventory-empty" data-i18n="product_detail_no_inventory">'
        + t('product_detail_no_inventory', 'Este producto no tiene disponibilidad en ninguna tienda.') + '</p>';
      return;
    }

    var html = '<table class="inventory-table"><thead><tr>'
      + '<th data-i18n="product_detail_col_store">' + t('product_detail_col_store', 'Tienda') + '</th>'
      + '<th data-i18n="product_detail_col_shelf">' + t('product_detail_col_shelf', 'Estantería') + '</th>'
      + '<th data-i18n="product_detail_col_shelf_count">' + t('product_detail_col_shelf_count', 'Stock en Shelf') + '</th>'
      + '<th data-i18n="product_detail_col_actions">' + t('product_detail_col_actions', 'Acciones') + '</th>'
      + '</tr></thead><tbody>';

    groups.forEach(function (group, index) {
      var storeId = escapeHtml(group.store_id);
      var storeName = escapeHtml(group.store_name);
      var flagUrl = 'https://flagcdn.com/20x15/' + (group.store_country || '').toLowerCase() + '.png';
      var totalStockClass = stockClass(group.total_stock);

      // Group header row
      html += '<tr class="inventory-group-header' + (index > 0 ? ' inventory-group-start' : '') + '" data-store-id="' + storeId + '">'
        + '<td colspan="4">'
        + '<div class="inventory-group-header-inner">'
        + '<span class="store-name-group"><i class="fas fa-store" aria-hidden="true"></i> '
        + '<img src="' + escapeHtml(flagUrl) + '" alt="' + escapeHtml(group.store_country) + '" class="store-flag-sm" onerror="this.style.display=\'none\'"> '
        + storeName + '</span>'
        + '<span class="badge badge-stock ' + totalStockClass + '">'
        + t('product_detail_total_stock', 'Total') + ': <strong>' + escapeHtml(String(group.total_stock)) + '</strong> uds.'
        + '</span>'
        + '<button class="btn-link btn-add-shelf" type="button" data-store-id="' + storeId + '" data-store-name="' + storeName + '">'
        + '<i class="fas fa-plus" aria-hidden="true"></i> '
        + '<span data-i18n="product_detail_add_to_shelf">' + t('product_detail_add_to_shelf', 'Añadir a otra Shelf') + '</span>'
        + '</button>'
        + '</div>'
        + '<div class="add-shelf-inline" id="add-shelf-' + storeId.replace(/[^a-z0-9]/gi, '_') + '" hidden>'
        + '<select class="shelf-select" data-store-id="' + storeId + '"><option value="">' + t('product_detail_loading_shelves', 'Cargando…') + '</option></select>'
        + '<input type="number" class="shelf-count-input" min="0" value="0" style="width:5rem;" />'
        + '<button class="btn-primary btn-small btn-confirm-add" type="button" data-store-id="' + storeId + '" disabled>'
        + t('product_detail_confirm_add', 'Confirmar') + '</button>'
        + '<button class="btn-secondary btn-small btn-cancel-add" type="button" data-store-id="' + storeId + '">'
        + t('product_detail_cancel_add', 'Cancelar') + '</button>'
        + '</div>'
        + '</td>'
        + '</tr>';

      // Shelf detail rows
      group.shelves.forEach(function (shelf) {
        var itemId = escapeHtml(shelf.item_id);
        var shelfClass = stockClass(shelf.shelfCount);
        html += '<tr class="inventory-detail-row" data-item-id="' + itemId + '" data-store-id="' + storeId + '">'
          + '<td></td>'
          + '<td><i class="fas fa-layer-group" aria-hidden="true"></i> ' + escapeHtml(shelf.shelf_name) + '</td>'
          + '<td class="shelf-count-cell">'
          + '<span class="badge badge-count shelf-count-display ' + shelfClass + '">' + escapeHtml(String(shelf.shelfCount)) + '</span>'
          + '<span class="shelf-count-edit" hidden>'
          + '<input type="number" class="shelf-count-inline" min="0" value="' + escapeHtml(String(shelf.shelfCount)) + '" style="width:5rem;" />'
          + '<button class="btn-primary btn-small btn-save-count" type="button" data-item-id="' + itemId + '">' + t('product_detail_save', 'OK') + '</button>'
          + '<button class="btn-secondary btn-small btn-cancel-count" type="button" data-item-id="' + itemId + '">' + t('product_detail_cancel_edit', 'X') + '</button>'
          + '</span>'
          + '</td>'
          + '<td class="inventory-actions">'
          + '<button class="btn-secondary btn-small btn-edit-count" type="button" data-item-id="' + itemId + '">'
          + '<i class="fas fa-pen" aria-hidden="true"></i> ' + t('products_edit', 'Editar') + '</button> '
          + '<button class="btn-danger btn-small btn-delete-item" type="button" data-item-id="' + itemId + '">'
          + '<i class="fas fa-trash" aria-hidden="true"></i> ' + t('products_delete', 'Borrar') + '</button>'
          + '</td>'
          + '</tr>';
      });
    });

    html += '</tbody></table>';
    container.innerHTML = html;
    attachInventoryHandlers();
  }

  function reloadInventory() {
    return fetch('/api/inventory?product=' + encodeURIComponent(PRODUCT_ID))
      .then(function (r) { return r.json(); })
      .then(function (items) {
        // Rebuild groups client-side from refreshed items
        if (!items.length) {
          renderInventory([]);
          return;
        }
        // Fetch all store & shelf data for the current items
        var storeIds = [...new Set(items.map(function (i) { return i.refStore; }))];
        var shelfIds = [...new Set(items.map(function (i) { return i.refShelf; }))];

        return Promise.all([
          Promise.all(storeIds.map(function (sid) { return fetch('/api/stores/' + encodeURIComponent(sid)).then(function (r) { return r.ok ? r.json() : {id: sid, name: sid}; }); })),
          Promise.all(shelfIds.map(function (shid) { return fetch('/api/shelves/' + encodeURIComponent(shid)).then(function (r) { return r.ok ? r.json() : {id: shid, name: shid}; }); }))
        ]).then(function (results) {
          var storesMap = {};
          results[0].forEach(function (s) { storesMap[s.id] = s; });
          var shelvesMap = {};
          results[1].forEach(function (sh) { shelvesMap[sh.id] = sh; });

          var grouped = {};
          items.forEach(function (item) {
            var sid = item.refStore;
            if (!grouped[sid]) {
              var store = storesMap[sid] || {};
              grouped[sid] = {store_id: sid, store_name: store.name || sid, store_image: store.image || '', store_country: store.countryCode || '', total_stock: 0, shelves: []};
            }
            var shelf = shelvesMap[item.refShelf] || {};
            var sc = item.shelfCount || 0;
            grouped[sid].total_stock += sc;
            grouped[sid].shelves.push({item_id: item.id, shelf_id: item.refShelf, shelf_name: shelf.name || item.refShelf, shelfCount: sc});
          });

          renderInventory(Object.values(grouped).sort(function (a, b) { return a.store_name.localeCompare(b.store_name); }));
        });
      });
  }

  function attachInventoryHandlers() {
    // "Añadir a otra Shelf" button
    container.querySelectorAll('.btn-add-shelf').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var storeId = btn.getAttribute('data-store-id');
        var safeId = storeId.replace(/[^a-z0-9]/gi, '_');
        var panel = document.getElementById('add-shelf-' + safeId);
        if (!panel) return;
        panel.hidden = false;
        btn.hidden = true;
        // Load available shelves
        var sel = panel.querySelector('.shelf-select');
        var confirmBtn = panel.querySelector('.btn-confirm-add');
        sel.innerHTML = '<option value="">' + t('product_detail_loading_shelves', 'Cargando…') + '</option>';
        confirmBtn.disabled = true;
        fetch('/api/shelves?store=' + encodeURIComponent(storeId) + '&excludeProduct=' + encodeURIComponent(PRODUCT_ID))
          .then(function (r) { return r.json(); })
          .then(function (shelves) {
            if (!shelves.length) {
              sel.innerHTML = '<option value="">' + t('product_detail_no_shelves_available', 'Todas las estanterías ya contienen este producto') + '</option>';
              confirmBtn.disabled = true;
            } else {
              sel.innerHTML = '<option value="">--</option>' + shelves.map(function (sh) {
                return '<option value="' + escapeHtml(sh.id) + '">' + escapeHtml(sh.name) + '</option>';
              }).join('');
              sel.addEventListener('change', function () {
                confirmBtn.disabled = !sel.value;
              });
            }
          })
          .catch(function () {
            sel.innerHTML = '<option value="">' + t('product_detail_error_load_shelves', 'Error al cargar estanterías') + '</option>';
            confirmBtn.disabled = true;
          });
      });
    });

    // Cancel "añadir"
    container.querySelectorAll('.btn-cancel-add').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var storeId = btn.getAttribute('data-store-id');
        var safeId = storeId.replace(/[^a-z0-9]/gi, '_');
        var panel = document.getElementById('add-shelf-' + safeId);
        if (panel) panel.hidden = true;
        var addBtn = container.querySelector('.btn-add-shelf[data-store-id="' + storeId + '"]');
        if (addBtn) addBtn.hidden = false;
      });
    });

    // Confirm "añadir"
    container.querySelectorAll('.btn-confirm-add').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var storeId = btn.getAttribute('data-store-id');
        var safeId = storeId.replace(/[^a-z0-9]/gi, '_');
        var panel = document.getElementById('add-shelf-' + safeId);
        var sel = panel.querySelector('.shelf-select');
        var countInput = panel.querySelector('.shelf-count-input');
        if (!sel.value) return;
        btn.disabled = true;
        fetch('/api/inventory', {
          method: 'POST',
          headers: {'Content-Type': 'application/json'},
          body: JSON.stringify({
            refStore: storeId,
            refShelf: sel.value,
            refProduct: PRODUCT_ID,
            shelfCount: parseInt(countInput.value, 10) || 0,
            stockCount: parseInt(countInput.value, 10) || 0
          })
        }).then(function (r) {
          if (!r.ok) throw new Error('save failed');
          return reloadInventory();
        }).catch(function () {
          alert(t('product_detail_error_save_inventory', 'No se pudo añadir el ítem de inventario'));
          btn.disabled = false;
        });
      });
    });

    // Edit shelfCount (inline)
    container.querySelectorAll('.btn-edit-count').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var row = btn.closest('tr');
        var display = row.querySelector('.shelf-count-display');
        var editSpan = row.querySelector('.shelf-count-edit');
        if (display) display.hidden = true;
        if (editSpan) editSpan.hidden = false;
        btn.hidden = true;
        var delBtn = row.querySelector('.btn-delete-item');
        if (delBtn) delBtn.hidden = true;
      });
    });

    // Cancel shelfCount edit
    container.querySelectorAll('.btn-cancel-count').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var row = btn.closest('tr');
        var display = row.querySelector('.shelf-count-display');
        var editSpan = row.querySelector('.shelf-count-edit');
        if (display) display.hidden = false;
        if (editSpan) editSpan.hidden = true;
        var editBtn = row.querySelector('.btn-edit-count');
        if (editBtn) editBtn.hidden = false;
        var delBtn = row.querySelector('.btn-delete-item');
        if (delBtn) delBtn.hidden = false;
      });
    });

    // Save shelfCount
    container.querySelectorAll('.btn-save-count').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var itemId = btn.getAttribute('data-item-id');
        var row = btn.closest('tr');
        var input = row.querySelector('.shelf-count-inline');
        var newCount = parseInt(input.value, 10);
        if (isNaN(newCount) || newCount < 0) return;
        fetch('/api/inventory/' + encodeURIComponent(itemId), {
          method: 'PUT',
          headers: {'Content-Type': 'application/json'},
          body: JSON.stringify({shelfCount: newCount})
        }).then(function (r) {
          if (!r.ok) throw new Error('update failed');
          return reloadInventory();
        }).catch(function () {
          alert(t('product_detail_error_save_inventory', 'No se pudo guardar el cambio'));
        });
      });
    });

    // Delete inventory item
    container.querySelectorAll('.btn-delete-item').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var itemId = btn.getAttribute('data-item-id');
        if (!window.confirm(t('product_detail_confirm_delete_item', '¿Eliminar este ítem de inventario?'))) return;
        fetch('/api/inventory/' + encodeURIComponent(itemId), {method: 'DELETE'})
          .then(function (r) {
            if (!r.ok) throw new Error('delete failed');
            return reloadInventory();
          }).catch(function () {
            alert(t('product_detail_error_delete_inventory', 'No se pudo borrar el ítem de inventario'));
          });
      });
    });
  }

  // -------------------------------------------------------------------------
  // Product edit modal
  // -------------------------------------------------------------------------
  var modal = document.getElementById('product-modal');
  var form = document.getElementById('product-form');

  function openEditForm() {
    form.reset();
    document.getElementById('product-id').value = PRODUCT.id;
    document.getElementById('name').value = PRODUCT.name || '';
    document.getElementById('price').value = PRODUCT.price != null ? PRODUCT.price : '';
    document.getElementById('size').value = PRODUCT.size || '';
    document.getElementById('originCountry').value = PRODUCT.originCountry || '';
    document.getElementById('color').value = /^#[0-9A-Fa-f]{6}$/.test(PRODUCT.color || '') ? PRODUCT.color : '#4a90d9';
    var resolvedImage = imageForProduct(PRODUCT.name, PRODUCT.image);
    document.getElementById('image').value = resolvedImage;
    document.getElementById('existing-image').value = resolvedImage;
    modal.hidden = false;
  }

  async function saveProduct(event) {
    event.preventDefault();
    if (!form.checkValidity()) { form.reportValidity(); return; }
    var color = document.getElementById('color').value;
    if (!/^#[0-9A-Fa-f]{6}$/.test(color)) { alert(t('products_error_color', 'Invalid hex color.')); return; }
    var imageUrl = document.getElementById('image').value.trim();
    var existingImage = document.getElementById('existing-image').value;
    var typedName = document.getElementById('name').value.trim();
    var payload = {
      name: typedName,
      price: Number(document.getElementById('price').value),
      size: document.getElementById('size').value,
      originCountry: document.getElementById('originCountry').value.trim(),
      color: color,
      image: imageForProduct(typedName, imageUrl || existingImage)
    };
    var response = await fetch('/api/products/' + encodeURIComponent(PRODUCT.id), {
      method: 'PUT',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify(payload)
    });
    if (!response.ok) { alert(t('products_error_save', 'Could not save product.')); return; }
    // Update local state and reflect in header
    var updated = await response.json();
    Object.assign(PRODUCT, updated);
    modal.hidden = true;
    // Reload page to refresh header
    window.location.reload();
  }

  async function deleteProduct() {
    if (!window.confirm(t('products_confirm_delete', 'Are you sure you want to delete this product?'))) return;
    var response = await fetch('/api/products/' + encodeURIComponent(PRODUCT.id), {method: 'DELETE'});
    if (!response.ok) { alert(t('products_error_delete', 'Could not delete product.')); return; }
    window.location.href = '/products';
  }

  document.getElementById('btn-edit-product').addEventListener('click', openEditForm);
  document.getElementById('btn-delete-product').addEventListener('click', deleteProduct);
  document.getElementById('btn-cancel').addEventListener('click', function () { modal.hidden = true; });
  document.getElementById('product-modal-close').addEventListener('click', function () { modal.hidden = true; });
  form.addEventListener('submit', saveProduct);

  // -------------------------------------------------------------------------
  // Initial render
  // -------------------------------------------------------------------------
  document.addEventListener('DOMContentLoaded', function () {
    renderInventory(INVENTORY_GROUPS);
  });
}());
</script>
{% endblock %}

/* ============================================================
   theme.css — CSS-first theming via data-theme attribute
   All colors are declared as CSS custom properties.
   JS only toggles [data-theme] on <html> and persists to localStorage.
   ============================================================ */

/* ---------- Light theme (default) ---------- */
:root,
:root[data-theme="light"] {
  --bg:           #f4f4f9;
  --bg-alt:       #ffffff;
  --bg-nav:       #1a1a2e;
  --fg:           #1a1a2e;
  --fg-muted:     #555577;
  --accent:       #4a90d9;
  --accent-hover: #2f72bb;
  --border:       #d0d0e0;
  --shadow:       rgba(0, 0, 0, 0.08);
  --nav-fg:       #e0e0f0;
  --nav-active:   #4a90d9;
  --nav-hover-bg: rgba(255, 255, 255, 0.08);
  --footer-bg:    #1a1a2e;
  --footer-fg:    #a0a0c0;
  --btn-bg:       #4a90d9;
  --btn-fg:       #ffffff;
  --btn-border:   transparent;
  --card-bg:      #ffffff;
  --card-shadow:  0 4px 12px rgba(0, 0, 0, 0.08);
  --badge-bg:     #e8f0fb;
  --badge-fg:     #2f72bb;
}

/* ---------- Dark theme ---------- */
:root[data-theme="dark"] {
  --bg:           #0f0f1a;
  --bg-alt:       #1a1a2e;
  --bg-nav:       #0a0a14;
  --fg:           #e0e0f0;
  --fg-muted:     #8888aa;
  --accent:       #5ba3f5;
  --accent-hover: #7dbcff;
  --border:       #2a2a40;
  --shadow:       rgba(0, 0, 0, 0.4);
  --nav-fg:       #c0c0e0;
  --nav-active:   #5ba3f5;
  --nav-hover-bg: rgba(255, 255, 255, 0.05);
  --footer-bg:    #0a0a14;
  --footer-fg:    #666688;
  --btn-bg:       #2a3a5a;
  --btn-fg:       #c0d8ff;
  --btn-border:   #3a4a7a;
  --card-bg:      #1a1a2e;
  --card-shadow:  0 4px 12px rgba(0, 0, 0, 0.4);
  --badge-bg:     #1e2a40;
  --badge-fg:     #7dbcff;
}

/* ============================================================
   Base reset & common styles
   ============================================================ */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  font-size: 16px;
  line-height: 1.6;
  background-color: var(--bg);
  color: var(--fg);
  transition: background-color 0.25s ease, color 0.25s ease;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

a {
  color: var(--accent);
  text-decoration: none;
}

a:hover {
  color: var(--accent-hover);
  text-decoration: underline;
}

/* ============================================================
   Navbar
   ============================================================ */

.navbar {
  position: sticky;
  top: 0;
  z-index: 1000;
  background-color: var(--bg-nav);
  color: var(--nav-fg);
  box-shadow: 0 2px 8px var(--shadow);
  transition: background-color 0.25s ease;
}

.navbar-inner {
  display: flex;
  align-items: center;
  max-width: 1280px;
  margin: 0 auto;
  padding: 0 1.5rem;
  height: 3.5rem;
  gap: 0.5rem;
}

.navbar-brand {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--nav-fg);
  white-space: nowrap;
  margin-right: 1.5rem;
  text-decoration: none;
  letter-spacing: 0.03em;
}

.navbar-brand:hover {
  color: var(--nav-active);
  text-decoration: none;
}

.navbar-brand i {
  margin-right: 0.4rem;
  color: var(--nav-active);
}

.navbar-links {
  display: flex;
  align-items: center;
  list-style: none;
  margin: 0;
  padding: 0;
  gap: 0.25rem;
  flex: 1;
}

.navbar-links li a {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.4rem 0.85rem;
  border-radius: 6px;
  color: var(--nav-fg);
  font-size: 0.9rem;
  font-weight: 500;
  white-space: nowrap;
  transition: background-color 0.15s ease, color 0.15s ease;
  text-decoration: none;
}

.navbar-links li a:hover {
  background-color: var(--nav-hover-bg);
  color: var(--nav-active);
  text-decoration: none;
}

/* Active link — set by JS via class "active" */
.navbar-links li a.active {
  color: var(--nav-active);
  border-bottom: 2px solid var(--nav-active);
  font-weight: 700;
}

/* ---- Toggle buttons ---- */
.navbar-controls {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-left: auto;
}

.btn-toggle {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.35rem 0.75rem;
  border-radius: 6px;
  background-color: var(--btn-bg);
  color: var(--btn-fg);
  border: 1px solid var(--btn-border);
  font-size: 0.82rem;
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.15s ease, color 0.15s ease, border-color 0.15s ease;
  white-space: nowrap;
}

.btn-toggle:hover {
  background-color: var(--accent);
  color: #fff;
  border-color: var(--accent);
}

/* Hide the light-icon when in light mode and dark-icon when in dark mode */
:root[data-theme="light"] #icon-dark  { display: inline; }
:root[data-theme="light"] #icon-light { display: none; }
:root[data-theme="dark"]  #icon-dark  { display: none; }
:root[data-theme="dark"]  #icon-light { display: inline; }

/* ============================================================
   Main content wrapper
   ============================================================ */

.main-content {
  flex: 1;
  max-width: 1280px;
  width: 100%;
  margin: 0 auto;
  padding: 2rem 1.5rem;
}

/* ============================================================
   Cards
   ============================================================ */

.card {
  background-color: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  padding: 1.5rem;
  margin-bottom: 1.5rem;
  transition: background-color 0.25s ease, border-color 0.25s ease;
}

/* ============================================================
   Status banners (health indicator)
   ============================================================ */

.status {
  padding: 0.75rem 1rem;
  margin-top: 1rem;
  border-radius: 6px;
  font-size: 0.9rem;
}

.status.ok {
  background-color: #d4edda;
  color: #155724;
  border: 1px solid #c3e6cb;
}

.status.error {
  background-color: #f8d7da;
  color: #721c24;
  border: 1px solid #f5c6cb;
}

:root[data-theme="dark"] .status.ok {
  background-color: #1a3a2a;
  color: #6fde9e;
  border-color: #2a5a40;
}

:root[data-theme="dark"] .status.error {
  background-color: #3a1a1a;
  color: #f08080;
  border-color: #5a2a2a;
}

/* ============================================================
   Section headers
   ============================================================ */

.section-header {
  margin-bottom: 1.5rem;
}

.section-header h1 {
  font-size: 1.8rem;
  font-weight: 700;
  margin: 0 0 0.25rem;
  color: var(--fg);
}

.section-header p {
  font-size: 1rem;
  color: var(--fg-muted);
  margin: 0;
}

/* ============================================================
   Footer
   ============================================================ */

.footer {
  background-color: var(--footer-bg);
  color: var(--footer-fg);
  padding: 1.25rem 1.5rem;
  text-align: center;
  font-size: 0.82rem;
  transition: background-color 0.25s ease;
}

.footer a {
  color: var(--accent);
}

/* ============================================================
   Utility
   ============================================================ */

.text-muted {
  color: var(--fg-muted);
}

.badge {
  display: inline-block;
  padding: 0.2em 0.6em;
  border-radius: 4px;
  font-size: 0.78rem;
  font-weight: 600;
  background-color: var(--badge-bg);
  color: var(--badge-fg);
}

/* ============================================================
   Statistics Cards Grid
   ============================================================ */

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
}

.stat-card {
  display: flex;
  align-items: center;
  padding: 1.5rem;
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  cursor: pointer;
}

.stat-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 16px var(--shadow);
}

.stat-icon {
  font-size: 2.5rem;
  margin-right: 1.5rem;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 80px;
  height: 80px;
  border-radius: 8px;
}

.stat-content h3 {
  margin: 0 0 0.5rem;
  font-size: 0.95rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  opacity: 0.85;
}

.stat-number {
  margin: 0;
  font-size: 2rem;
  font-weight: 700;
}

/* Color schemes for each stat card */
.stat-stores {
  background: linear-gradient(135deg, #FF6B6B 0%, #FF8E8E 100%);
  color: #ffffff;
}

.stat-stores .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

.stat-products {
  background: linear-gradient(135deg, #4ECDC4 0%, #6FE0DD 100%);
  color: #ffffff;
}

.stat-products .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

.stat-employees {
  background: linear-gradient(135deg, #95E1D3 0%, #B5EFE1 100%);
  color: #1a1a2e;
}

.stat-employees .stat-icon {
  background-color: rgba(26, 26, 46, 0.1);
  color: #1a1a2e;
}

.stat-inventory {
  background: linear-gradient(135deg, #F38181 0%, #F5A6A6 100%);
  color: #ffffff;
}

.stat-inventory .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

/* Dark theme adjustments for stat cards */
:root[data-theme="dark"] .stat-stores {
  background: linear-gradient(135deg, #c94545 0%, #d95959 100%);
}

:root[data-theme="dark"] .stat-products {
  background: linear-gradient(135deg, #3a9b95 0%, #4db5ac 100%);
}

:root[data-theme="dark"] .stat-employees {
  background: linear-gradient(135deg, #6fb8a6 0%, #86cbb5 100%);
  color: #ffffff;
}

:root[data-theme="dark"] .stat-employees .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

:root[data-theme="dark"] .stat-inventory {
  background: linear-gradient(135deg, #c96668 0%, #d97d7e 100%);
}

/* ============================================================
   Mermaid Diagram Container
   ============================================================ */

.mermaid-container {
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 1.5rem;
  overflow-x: auto;
  background-color: var(--bg-alt);
  border-radius: 8px;
  border: 1px solid var(--border);
  min-height: 400px;
}

.mermaid {
  display: flex;
  justify-content: center;
  align-items: center;
  max-width: 100%;
}

/* SVG text in Mermaid diagrams inherit text color from theme */
.mermaid svg {
  max-width: 100%;
  height: auto;
}

.mermaid text {
  fill: var(--fg);
}

.mermaid line,
.mermaid path,
.mermaid polyline,
.mermaid polygon {
  stroke: var(--fg-muted);
}

/* Dark theme adjustments for Mermaid */
:root[data-theme="dark"] .mermaid text {
  fill: var(--fg);
}

:root[data-theme="dark"] .mermaid line,
:root[data-theme="dark"] .mermaid path {
  stroke: var(--fg-muted);
}

/* ============================================================
   Products view
   ============================================================ */

.products-toolbar {
  display: flex;
  justify-content: flex-start;
}

.modal[hidden] {
  display: none;
}

.modal {
  position: fixed;
  inset: 0;
  z-index: 2000;
}

.modal__backdrop {
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.45);
}

.modal__panel {
  position: relative;
  width: min(820px, calc(100% - 2rem));
  max-height: calc(100vh - 4rem);
  overflow-y: auto;
  margin: 2rem auto;
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  padding: 1.25rem;
}

.products-table-wrap {
  overflow-x: auto;
}

.products-table {
  width: 100%;
  border-collapse: collapse;
  min-width: 800px;
}

.products-table th,
.products-table td {
  border-bottom: 1px solid var(--border);
  padding: 0.75rem;
  text-align: left;
  vertical-align: middle;
}

.products-table th {
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--fg-muted);
}

.product-thumb {
  width: 52px;
  height: 52px;
  border-radius: 8px;
  object-fit: cover;
  border: 1px solid var(--border);
}

.color-chip {
  display: inline-block;
  width: 1rem;
  height: 1rem;
  border-radius: 3px;
  border: 1px solid var(--border);
  margin-right: 0.35rem;
  vertical-align: middle;
}

.form-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1rem;
}

.form-grid label,
.form-grid fieldset {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  margin: 0;
}

.form-grid input,
.form-grid select {
  background: var(--bg-alt);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 0.5rem 0.65rem;
}

.inline-label {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
}

.form-actions {
  margin-top: 1rem;
  display: flex;
  gap: 0.6rem;
}

.btn-primary,
.btn-secondary,
.btn-danger {
  border: 1px solid var(--btn-border);
  border-radius: 6px;
  padding: 0.45rem 0.75rem;
  cursor: pointer;
  font-weight: 600;
}

.btn-primary {
  background: var(--accent);
  color: #fff;
  border-color: var(--accent);
}

.btn-secondary {
  background: var(--bg-alt);
  color: var(--fg);
  border-color: var(--border);
}

.btn-danger {
  background: #d9534f;
  color: #fff;
  border-color: #d9534f;
}

.btn-small {
  font-size: 0.8rem;
  padding: 0.32rem 0.55rem;
}

.product-row-clickable {
  cursor: pointer;
}

.product-row-clickable:hover td {
  background-color: var(--bg-alt);
}

/* ============================================================
   Product detail view
   ============================================================ */

.product-detail-card {
  padding: 1.4rem;
}

.product-detail-hero {
  display: grid;
  grid-template-columns: minmax(220px, 320px) 1fr;
  gap: 1.5rem;
  align-items: stretch;
}

.product-detail-media {
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 1rem;
  box-shadow: 0 4px 10px var(--shadow);
  min-height: 260px;
}

.product-detail-img {
  width: 100%;
  max-width: 260px;
  height: 220px;
  object-fit: cover;
  border-radius: 12px;
  transition: transform 0.22s ease;
}

.product-detail-media:hover .product-detail-img {
  transform: scale(1.05);
}

.product-detail-meta {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.product-detail-name {
  margin: 0;
  color: var(--fg);
  font-size: 1.8rem;
}

.product-attr-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.product-attr-item {
  display: flex;
  align-items: center;
  gap: 0.55rem;
  background: var(--bg-alt);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.55rem 0.75rem;
}

.product-attr-item i {
  color: var(--accent);
  width: 1rem;
  text-align: center;
}

.attr-label {
  font-weight: 700;
  color: var(--fg);
}

.attr-value {
  margin-left: auto;
  color: var(--fg);
}

.color-attr-item .attr-value {
  margin-left: 0;
}

.product-color-swatch {
  width: 24px;
  height: 24px;
  border-radius: 6px;
  border: 1px solid var(--border);
  margin-left: auto;
  box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.2);
}

.product-detail-actions {
  margin-top: auto;
  display: flex;
  justify-content: flex-end;
  gap: 0.55rem;
}

/* ============================================================
   Product inventory table detail
   ============================================================ */

.inventory-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}

.inventory-table th,
.inventory-table td {
  border-bottom: 1px solid var(--border);
  padding: 0.55rem 0.7rem;
  vertical-align: middle;
}

.inventory-table th {
  color: var(--fg-muted);
  font-size: 0.84rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.inventory-group-header td {
  background: color-mix(in srgb, var(--accent) 9%, var(--card-bg));
  font-weight: 700;
  min-height: 64px;
  border-bottom: 1px solid var(--border);
}

.inventory-group-start td {
  border-top: 10px solid var(--bg);
}

.inventory-group-header-inner {
  display: flex;
  align-items: center;
  gap: 0.6rem;
  flex-wrap: wrap;
}

.store-name-group {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
}

.store-flag-sm {
  border-radius: 2px;
}

.inventory-detail-row td {
  background: var(--card-bg);
}

.inventory-detail-row td:nth-child(2) {
  padding-left: 2.2rem;
}

.inventory-actions {
  text-align: right;
  white-space: nowrap;
}

.inventory-actions .btn-small {
  padding: 0.25rem 0.48rem;
}

.badge-stock,
.badge-count {
  border-radius: 999px;
  border: 0;
  font-weight: 700;
  padding: 0.2rem 0.6rem;
}

.badge-stock-high,
.badge-count.badge-stock-high {
  background: #1f9d55;
  color: #fff;
}

.badge-stock-medium,
.badge-count.badge-stock-medium {
  background: #d97706;
  color: #fff;
}

.badge-stock-low,
.badge-count.badge-stock-low {
  background: #dc2626;
  color: #fff;
}

.add-shelf-inline {
  margin-top: 0.65rem;
  padding: 0.65rem;
  border: 1px dashed var(--border);
  border-radius: 10px;
  background: var(--card-bg);
}

.add-shelf-inline select,
.add-shelf-inline input {
  background: var(--bg-alt);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 0.35rem 0.45rem;
}

@media (max-width: 900px) {
  .product-detail-hero {
    grid-template-columns: 1fr;
  }

  .product-detail-media {
    min-height: 200px;
  }

  .product-detail-img {
    max-width: 100%;
    width: min(100%, 320px);
    height: 200px;
  }

  .product-detail-actions {
    justify-content: flex-start;
  }
}

