/* ============================================================
   theme.css — CSS-first theming via data-theme attribute
   All colors are declared as CSS custom properties.
   JS only toggles [data-theme] on <html> and persists to localStorage.
   ============================================================ */

/* ---------- Light theme (default) ---------- */
:root,
:root[data-theme="light"] {
  --bg:           #f4f4f9;
  --bg-alt:       #ffffff;
  --bg-nav:       #1a1a2e;
  --fg:           #1a1a2e;
  --fg-muted:     #555577;
  --accent:       #4a90d9;
  --accent-hover: #2f72bb;
  --border:       #d0d0e0;
  --shadow:       rgba(0, 0, 0, 0.08);
  --nav-fg:       #e0e0f0;
  --nav-active:   #4a90d9;
  --nav-hover-bg: rgba(255, 255, 255, 0.08);
  --footer-bg:    #1a1a2e;
  --footer-fg:    #a0a0c0;
  --btn-bg:       #4a90d9;
  --btn-fg:       #ffffff;
  --btn-border:   transparent;
  --card-bg:      #ffffff;
  --card-shadow:  0 4px 12px rgba(0, 0, 0, 0.08);
  --badge-bg:     #e8f0fb;
  --badge-fg:     #2f72bb;
}

/* ---------- Dark theme ---------- */
:root[data-theme="dark"] {
  --bg:           #0f0f1a;
  --bg-alt:       #1a1a2e;
  --bg-nav:       #0a0a14;
  --fg:           #e0e0f0;
  --fg-muted:     #8888aa;
  --accent:       #5ba3f5;
  --accent-hover: #7dbcff;
  --border:       #2a2a40;
  --shadow:       rgba(0, 0, 0, 0.4);
  --nav-fg:       #c0c0e0;
  --nav-active:   #5ba3f5;
  --nav-hover-bg: rgba(255, 255, 255, 0.05);
  --footer-bg:    #0a0a14;
  --footer-fg:    #666688;
  --btn-bg:       #2a3a5a;
  --btn-fg:       #c0d8ff;
  --btn-border:   #3a4a7a;
  --card-bg:      #1a1a2e;
  --card-shadow:  0 4px 12px rgba(0, 0, 0, 0.4);
  --badge-bg:     #1e2a40;
  --badge-fg:     #7dbcff;
}

/* ============================================================
   Base reset & common styles
   ============================================================ */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  font-size: 16px;
  line-height: 1.6;
  background-color: var(--bg);
  color: var(--fg);
  transition: background-color 0.25s ease, color 0.25s ease;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

a {
  color: var(--accent);
  text-decoration: none;
}

a:hover {
  color: var(--accent-hover);
  text-decoration: underline;
}

/* ============================================================
   Navbar
   ============================================================ */

.navbar {
  position: sticky;
  top: 0;
  z-index: 1000;
  background-color: var(--bg-nav);
  color: var(--nav-fg);
  box-shadow: 0 2px 8px var(--shadow);
  transition: background-color 0.25s ease;
}

.navbar-inner {
  display: flex;
  align-items: center;
  max-width: 1280px;
  margin: 0 auto;
  padding: 0 1.5rem;
  height: 3.5rem;
  gap: 0.5rem;
}

.navbar-brand {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--nav-fg);
  white-space: nowrap;
  margin-right: 1.5rem;
  text-decoration: none;
  letter-spacing: 0.03em;
}

.navbar-brand:hover {
  color: var(--nav-active);
  text-decoration: none;
}

.navbar-brand i {
  margin-right: 0.4rem;
  color: var(--nav-active);
}

.navbar-links {
  display: flex;
  align-items: center;
  list-style: none;
  margin: 0;
  padding: 0;
  gap: 0.25rem;
  flex: 1;
}

.navbar-links li a {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.4rem 0.85rem;
  border-radius: 6px;
  color: var(--nav-fg);
  font-size: 0.9rem;
  font-weight: 500;
  white-space: nowrap;
  transition: background-color 0.15s ease, color 0.15s ease;
  text-decoration: none;
}

.navbar-links li a:hover {
  background-color: var(--nav-hover-bg);
  color: var(--nav-active);
  text-decoration: none;
}

/* Active link — set by JS via class "active" */
.navbar-links li a.active {
  color: var(--nav-active);
  border-bottom: 2px solid var(--nav-active);
  font-weight: 700;
}

/* ---- Toggle buttons ---- */
.navbar-controls {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-left: auto;
}

.btn-toggle {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.35rem 0.75rem;
  border-radius: 6px;
  background-color: var(--btn-bg);
  color: var(--btn-fg);
  border: 1px solid var(--btn-border);
  font-size: 0.82rem;
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.15s ease, color 0.15s ease, border-color 0.15s ease;
  white-space: nowrap;
}

.btn-toggle:hover {
  background-color: var(--accent);
  color: #fff;
  border-color: var(--accent);
}

/* Hide the light-icon when in light mode and dark-icon when in dark mode */
:root[data-theme="light"] #icon-dark  { display: inline; }
:root[data-theme="light"] #icon-light { display: none; }
:root[data-theme="dark"]  #icon-dark  { display: none; }
:root[data-theme="dark"]  #icon-light { display: inline; }

/* ============================================================
   Main content wrapper
   ============================================================ */

.main-content {
  flex: 1;
  max-width: 1280px;
  width: 100%;
  margin: 0 auto;
  padding: 2rem 1.5rem;
}

/* ============================================================
   Cards
   ============================================================ */

.card {
  background-color: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  padding: 1.5rem;
  margin-bottom: 1.5rem;
  transition: background-color 0.25s ease, border-color 0.25s ease;
}

/* ============================================================
   Status banners (health indicator)
   ============================================================ */

.status {
  padding: 0.75rem 1rem;
  margin-top: 1rem;
  border-radius: 6px;
  font-size: 0.9rem;
}

.status.ok {
  background-color: #d4edda;
  color: #155724;
  border: 1px solid #c3e6cb;
}

.status.error {
  background-color: #f8d7da;
  color: #721c24;
  border: 1px solid #f5c6cb;
}

:root[data-theme="dark"] .status.ok {
  background-color: #1a3a2a;
  color: #6fde9e;
  border-color: #2a5a40;
}

:root[data-theme="dark"] .status.error {
  background-color: #3a1a1a;
  color: #f08080;
  border-color: #5a2a2a;
}

/* ============================================================
   Section headers
   ============================================================ */

.section-header {
  margin-bottom: 1.5rem;
}

.section-header h1 {
  font-size: 1.8rem;
  font-weight: 700;
  margin: 0 0 0.25rem;
  color: var(--fg);
}

.section-header p {
  font-size: 1rem;
  color: var(--fg-muted);
  margin: 0;
}

/* ============================================================
   Footer
   ============================================================ */

.footer {
  background-color: var(--footer-bg);
  color: var(--footer-fg);
  padding: 1.25rem 1.5rem;
  text-align: center;
  font-size: 0.82rem;
  transition: background-color 0.25s ease;
}

.footer a {
  color: var(--accent);
}

/* ============================================================
   Utility
   ============================================================ */

.text-muted {
  color: var(--fg-muted);
}

.badge {
  display: inline-block;
  padding: 0.2em 0.6em;
  border-radius: 4px;
  font-size: 0.78rem;
  font-weight: 600;
  background-color: var(--badge-bg);
  color: var(--badge-fg);
}

/* ============================================================
   Statistics Cards Grid
   ============================================================ */

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
}

.stat-card {
  display: flex;
  align-items: center;
  padding: 1.5rem;
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  cursor: pointer;
}

.stat-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 16px var(--shadow);
}

.stat-icon {
  font-size: 2.5rem;
  margin-right: 1.5rem;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 80px;
  height: 80px;
  border-radius: 8px;
}

.stat-content h3 {
  margin: 0 0 0.5rem;
  font-size: 0.95rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  opacity: 0.85;
}

.stat-number {
  margin: 0;
  font-size: 2rem;
  font-weight: 700;
}

/* Color schemes for each stat card */
.stat-stores {
  background: linear-gradient(135deg, #FF6B6B 0%, #FF8E8E 100%);
  color: #ffffff;
}

.stat-stores .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

.stat-products {
  background: linear-gradient(135deg, #4ECDC4 0%, #6FE0DD 100%);
  color: #ffffff;
}

.stat-products .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

.stat-employees {
  background: linear-gradient(135deg, #95E1D3 0%, #B5EFE1 100%);
  color: #1a1a2e;
}

.stat-employees .stat-icon {
  background-color: rgba(26, 26, 46, 0.1);
  color: #1a1a2e;
}

.stat-inventory {
  background: linear-gradient(135deg, #F38181 0%, #F5A6A6 100%);
  color: #ffffff;
}

.stat-inventory .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

/* Dark theme adjustments for stat cards */
:root[data-theme="dark"] .stat-stores {
  background: linear-gradient(135deg, #c94545 0%, #d95959 100%);
}

:root[data-theme="dark"] .stat-products {
  background: linear-gradient(135deg, #3a9b95 0%, #4db5ac 100%);
}

:root[data-theme="dark"] .stat-employees {
  background: linear-gradient(135deg, #6fb8a6 0%, #86cbb5 100%);
  color: #ffffff;
}

:root[data-theme="dark"] .stat-employees .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

:root[data-theme="dark"] .stat-inventory {
  background: linear-gradient(135deg, #c96668 0%, #d97d7e 100%);
}

/* ============================================================
   Mermaid Diagram Container
   ============================================================ */

.mermaid-container {
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 1.5rem;
  overflow-x: auto;
  background-color: var(--bg-alt);
  border-radius: 8px;
  border: 1px solid var(--border);
  min-height: 400px;
}

.mermaid {
  display: flex;
  justify-content: center;
  align-items: center;
  max-width: 100%;
}

/* SVG text in Mermaid diagrams inherit text color from theme */
.mermaid svg {
  max-width: 100%;
  height: auto;
}

.mermaid text {
  fill: var(--fg);
}

.mermaid line,
.mermaid path,
.mermaid polyline,
.mermaid polygon {
  stroke: var(--fg-muted);
}

/* Dark theme adjustments for Mermaid */
:root[data-theme="dark"] .mermaid text {
  fill: var(--fg);
}

:root[data-theme="dark"] .mermaid line,
:root[data-theme="dark"] .mermaid path {
  stroke: var(--fg-muted);
}

/* ============================================================
   Products view
   ============================================================ */

.products-toolbar {
  display: flex;
  justify-content: flex-start;
}

.modal[hidden] {
  display: none;
}

.modal {
  position: fixed;
  inset: 0;
  z-index: 2000;
}

.modal__backdrop {
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.45);
}

.modal__panel {
  position: relative;
  width: min(820px, calc(100% - 2rem));
  max-height: calc(100vh - 4rem);
  overflow-y: auto;
  margin: 2rem auto;
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  padding: 1.25rem;
}

.products-table-wrap {
  overflow-x: auto;
}

.products-table {
  width: 100%;
  border-collapse: collapse;
  min-width: 800px;
}

.products-table th,
.products-table td {
  border-bottom: 1px solid var(--border);
  padding: 0.75rem;
  text-align: left;
  vertical-align: middle;
}

.products-table th {
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--fg-muted);
}

.product-thumb {
  width: 52px;
  height: 52px;
  border-radius: 8px;
  object-fit: cover;
  border: 1px solid var(--border);
}

.color-chip {
  display: inline-block;
  width: 1rem;
  height: 1rem;
  border-radius: 3px;
  border: 1px solid var(--border);
  margin-right: 0.35rem;
  vertical-align: middle;
}

.form-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1rem;
}

.form-grid label,
.form-grid fieldset {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
  margin: 0;
}

.form-grid input,
.form-grid select {
  background: var(--bg-alt);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 0.5rem 0.65rem;
}

.inline-label {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
}

.form-actions {
  margin-top: 1rem;
  display: flex;
  gap: 0.6rem;
}

.btn-primary,
.btn-secondary,
.btn-danger {
  border: 1px solid var(--btn-border);
  border-radius: 6px;
  padding: 0.45rem 0.75rem;
  cursor: pointer;
  font-weight: 600;
}

.btn-primary {
  background: var(--accent);
  color: #fff;
  border-color: var(--accent);
}

.btn-secondary {
  background: var(--bg-alt);
  color: var(--fg);
  border-color: var(--border);
}

.btn-danger {
  background: #d9534f;
  color: #fff;
  border-color: #d9534f;
}

.btn-small {
  font-size: 0.8rem;
  padding: 0.32rem 0.55rem;
}

.product-row-clickable {
  cursor: pointer;
}

.product-row-clickable:hover td {
  background-color: var(--bg-alt);
}

/* ============================================================
   Product detail view
   ============================================================ */

.product-detail-card {
  padding: 1.4rem;
}

.product-detail-hero {
  display: grid;
  grid-template-columns: minmax(220px, 320px) 1fr;
  gap: 1.5rem;
  align-items: stretch;
}

.product-detail-media {
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 1rem;
  box-shadow: 0 4px 10px var(--shadow);
  min-height: 260px;
}

.product-detail-img {
  width: 100%;
  max-width: 260px;
  height: 220px;
  object-fit: cover;
  border-radius: 12px;
  transition: transform 0.22s ease;
}

.product-detail-media:hover .product-detail-img {
  transform: scale(1.05);
}

.product-detail-meta {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.product-detail-name {
  margin: 0;
  color: var(--fg);
  font-size: 1.8rem;
}

.product-attr-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.product-attr-item {
  display: flex;
  align-items: center;
  gap: 0.55rem;
  background: var(--bg-alt);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.55rem 0.75rem;
}

.product-attr-item i {
  color: var(--accent);
  width: 1rem;
  text-align: center;
}

.attr-label {
  font-weight: 700;
  color: var(--fg);
}

.attr-value {
  margin-left: auto;
  color: var(--fg);
}

.color-attr-item .attr-value {
  margin-left: 0;
}

.product-color-swatch {
  width: 24px;
  height: 24px;
  border-radius: 6px;
  border: 1px solid var(--border);
  margin-left: auto;
  box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.2);
}

.product-detail-actions {
  margin-top: auto;
  display: flex;
  justify-content: flex-end;
  gap: 0.55rem;
}

/* ============================================================
   Product inventory table detail
   ============================================================ */

.inventory-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}

.inventory-table th,
.inventory-table td {
  border-bottom: 1px solid var(--border);
  padding: 0.55rem 0.7rem;
  vertical-align: middle;
}

.inventory-table th {
  color: var(--fg-muted);
  font-size: 0.84rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.inventory-group-header td {
  background: color-mix(in srgb, var(--accent) 9%, var(--card-bg));
  font-weight: 700;
  min-height: 64px;
  border-bottom: 1px solid var(--border);
}

.inventory-group-start td {
  border-top: 10px solid var(--bg);
}

.inventory-group-header-inner {
  display: flex;
  align-items: center;
  gap: 0.6rem;
  flex-wrap: wrap;
}

.inventory-group-header-inner .btn-add-shelf {
  margin-left: auto;
}

.store-name-group {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
}

.store-flag-sm {
  border-radius: 2px;
}

.inventory-detail-row td {
  background: var(--card-bg);
}

.inventory-detail-row td:nth-child(2) {
  padding-left: 0.7rem;
  text-align: center;
}

.inventory-table th:nth-child(2),
.inventory-table td:nth-child(2),
.inventory-table th:nth-child(3),
.inventory-table td:nth-child(3) {
  text-align: center;
}

.inventory-actions {
  text-align: right;
  white-space: nowrap;
}

.inventory-actions .btn-small {
  padding: 0.25rem 0.48rem;
}

.badge-stock,
.badge-count {
  border-radius: 999px;
  border: 0;
  font-weight: 700;
  padding: 0.2rem 0.6rem;
}

.badge-stock-high,
.badge-count.badge-stock-high {
  background: #1f9d55;
  color: #fff;
}

.badge-stock-medium,
.badge-count.badge-stock-medium {
  background: #d97706;
  color: #fff;
}

.badge-stock-low,
.badge-count.badge-stock-low {
  background: #dc2626;
  color: #fff;
}

